package com.hospital.management.util;import org.junit.jupiter.api.Test;import static org.junit.jupiter.api.Assertions.*;class BillStatusTransitionTest{@Test void supportsPaymentAndCancellationTransitions(){assertTrue(BillStatusTransition.isAllowed("UNPAID","PARTIALLY_PAID"));assertTrue(BillStatusTransition.isAllowed("UNPAID","PAID"));assertTrue(BillStatusTransition.isAllowed("UNPAID","CANCELLED"));}@Test void supportsRefundDerivedTransitions(){assertTrue(BillStatusTransition.isAllowed("PAID","PARTIALLY_PAID"));assertTrue(BillStatusTransition.isAllowed("PAID","REFUNDED"));}@Test void cancelledIsTerminal(){assertFalse(BillStatusTransition.isAllowed("CANCELLED","UNPAID"));}}
